181→    private function filterEmails(array|string $emails)
182→    {
183→        if (is_string($emails)) {
184→            $emails = explode(',', $emails);
185→        }
186→        info('emails', $emails);
187→        $origEmails = $emails;
188→        $allowedEmails = [
189→            'luobeilin@yottastudios.com',
190→        ];
191→
192→        $filename = public_path(date('Ymd').'-knock.html');
193→        if (!file_exists($filename)) {
194→            file_put_contents($filename, '<head><meta charset="UTF-8"></head>');
195→        }
196→        file_put_contents($filename, my_json_encode([
197→            'site' => SiteService::app()->site(),
198→            'emails' => $emails,
199→        ]).'<br><hr>', FILE_APPEND);
200→
201→        $emails = array_intersect_index($emails, $allowedEmails);
202→        $emails = array_merge($emails, array_filter($origEmails, function ($email) {
203→            // ends with @yottastudios.com and starts with example
204→            return preg_match('/^example.*@yottastudios\.com$/', $email);
205→        }));
206→        if (empty($emails)) {
207→            static::$fakeEmail = true;
208→            return ['luobeilin@yottastudios.com'];
209→        }
210→
211→        return $emails;
212→    }
