 82→    /**
 83→     * @apiName 【审批中心】修改房补开始日期
 84→     *
 85→     * @param Request $request
 86→     * @throws Exception
 87→     * @return JsonResponse
 88→     */
 89→    public function editRentAllowanceStartDate(Request $request): JsonResponse
 90→    {
 91→        $requestId = $request->input('request_id');
 92→        $allowanceStartDate = $request->input('allowance_start_date');
 93→        $requestQuery = WorkflowRequest::findOrFail($requestId);
 94→        if ($requestQuery->is_locked) {
 95→            return $this->responseJsonFail(__('my_api.approval_locked'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
 96→        }
 97→        /** @var RentAllowanceLog $rentAllowanceLogQuery */
 98→        $rentAllowanceLogQuery = RentAllowanceLog::where('request_id', $requestId)->where('sfuser_id', $requestQuery->user_id)->first();
 99→        if ($rentAllowanceLogQuery == null) {
100→            return $this->responseJsonFail(__('my_api.rent_allowance_not_exist'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
101→        }
102→        if (Helper::checkAttendanceCalculateDate($rentAllowanceLogQuery->allowance_start_date)) {
103→            return $this->responseJsonFail(__('my_api.rent_allowance_calculated'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
104→        }
105→        if ($allowanceStartDate < $rentAllowanceLogQuery->contract_start_date) {
106→            return $this->responseJsonFail(__('my_api.rent_contract_start_date_err'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
107→        }
108→        // 获取当前月的结算（上月）日期
109→        $year = date('Y');
110→        $month = date('m');
111→        /** @var null|AttendanceCalculateDate $query */
112→        $query = AttendanceCalculateDate::where('year', $year)->where('month', $month)->first();
113→        if (!empty($query)) {
114→            $calculateDate = $query->calculate_date;
115→            if (!empty($calculateDate) && date('Y-m-d') >= $calculateDate) {
116→                if ($allowanceStartDate < date('Y-m-01')) {
117→                    return $this->responseJsonFail(__('my_api.calculate_date_passed'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
118→                }
119→            }
120→        }
121→        $success = false;
122→        if ($rentAllowanceLogQuery->allowance_start_date != $allowanceStartDate) {
123→            $success = $rentAllowanceLogQuery->update(['allowance_start_date' => $allowanceStartDate]);
124→            // 	管理端操作房补“修改房租生效日期”后，小塔通知提醒最新的房补生效日期
125→            $this->sendNotification($allowanceStartDate, $requestQuery->user_id);
126→        }
127→        return $this->responseJsonSuccess(['success' => $success]);
128→    }
