362→    /**
363→     * 供 HR 端使用的预检接口，方便后续导入房补申请时生成新的数据。
364→     *
365→     * @apiName 【审批中心】流程预检接口，用于历史记录倒入
366→     *
367→     * @param Request $request
368→     * @throws \ReflectionException
369→     * @throws \App\Workflows\Exceptions\RequestNotFoundException
370→     * @throws \App\Workflows\Exceptions\WorkflowException
371→     * @return JsonResponse
372→     */
373→    public function preflightProcess(Request $request): JsonResponse
374→    {
375→        $input = Arr::only($request->all(), [
376→            'sfuser_id', 'process_key', 'context', 'version',
377→        ]);
378→
379→        if (!in_array($input['process_key'], static::ALLOWED_IMPORT_PROCESS_KEYS)) {
380→            return $this->responseJsonFail(__('my_api.can_not_preflight'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
381→        }
382→
383→        $version = $input['version'] ?? 0;
384→        WorkflowRequestService::checkInput($input['process_key'], $input['sfuser_id'], $input['context'], $version);
385→
386→        $data = WorkflowRequestService::preflightProcess($input['process_key'], $input['sfuser_id'], $input['context'], $version);
387→
388→        // 先把当前人的固定的几个花名取出来
389→        /** @var Sfuser $sfuser */
390→        $sfuser = Sfuser::where('id', $input['sfuser_id'])->select([
391→            'nickname', 'direct_supervisor_nickname', 'supervisor_nickname', 'ssc_nickname',
392→        ])->first();
393→
394→        // 将本次跟踪到的人的花名放在 all_nodes 中返回
395→        $data['all_nodes'] = [
396→            'profile' => [],
397→        ];
398→
399→        /**
400→         * @noinspection Duplicates
401→         */
402→        // 前端需要将 profile 里面的 key 翻译为对应的 type
403→        $profile = $sfuser->toArray();
404→        $maps = [
405→            WorkflowRequestStakeholder::REQUESTER_TYPE => 'nickname',
406→            WorkflowRequestStakeholder::DIRECT_SUPERVISOR_TYPE => 'direct_supervisor_nickname',
407→            WorkflowRequestStakeholder::SUPERVISOR_TYPE => 'supervisor_nickname',
408→            WorkflowRequestStakeholder::SSC_TYPE => 'ssc_nickname',
409→        ];
410→
411→        // 如果该审批中包含申请者、直接主管、部门主管、部门 SSC、直接取出当前人的这些花名
412→        // 以确保流程的流转或者花名的显式始终以发起时的为准
413→        $allTypes = $data['types'];
414→        $data['all_nodes']['nodes_types'] = $data['types'];
415→        foreach ($allTypes as $k => $type) {
416→            if (in_array($type, WorkflowRequestStakeholder::FIXED_MAPS)) {
417→                $data['all_nodes']['profile'][$type] = Arr::get($profile, $maps[$type]);
418→                unset($allTypes[$k]);
419→            }
420→        }
421→        $ccTypes = $data['all_cc_types'];
422→        foreach ($ccTypes as $k => $ccType) {
423→            if (in_array($ccType, WorkflowRequestStakeholder::FIXED_MAPS)) {
424→                $data['all_nodes']['profile'][$ccType] = Arr::get($profile, $maps[$ccType]);
425→                unset($ccTypes[$k]);
426→            }
427→        }
428→
429→        // 剩下的就是特殊花名了
430→        $specialNicknames = [];
431→        if ($allTypes) {
432→            $specialNicknames = Stakeholder::specialNicknames($allTypes, $input['sfuser_id'], $input['context']); // 然后取出当前预检包含的特殊审批的人的花名
433→            foreach ($specialNicknames as $type => $specialNickname) {
434→                $specialNicknames[$type] = Arr::first($specialNickname); // 操作节点中的人默认只取第一个，取多了也不管用
435→            }
436→        }
437→        $data['all_nodes']['nodes_special_nicknames'] = $specialNicknames;
438→
439→        // 获取的 cc_types，不用取第一个，直接返回一个数组即可
440→        $specialNicknames = [];
441→        if ($ccTypes) {
442→            $specialNicknames = Stakeholder::specialNicknames($ccTypes, $input['sfuser_id'], $input['context']);
443→        }
444→        $data['all_nodes']['cc_special_nicknames'] = $specialNicknames;
445→
446→        Arr::forget($data, 'types');
447→        Arr::forget($data, 'all_cc_types');
448→
449→        return $this->responseJsonSuccess($data);
450→    }
