452→    /**
453→     * @apiName 【审批中心】导入流程
454→     * @apiDescription 只支持房补导入
455→     *
456→     * @param \Illuminate\Http\Request $request
457→     * @throws \App\Workflows\Exceptions\RequestNotFoundException
458→     * @throws \App\Workflows\Exceptions\UserNotFoundException
459→     * @throws \App\Workflows\Exceptions\WorkflowException
460→     * @throws \ReflectionException
461→     * @throws \Throwable
462→     * @return \Illuminate\Http\JsonResponse
463→     */
464→    public function importProcess(Request $request): JsonResponse
465→    {
466→        $input = Arr::only($request->all(), [
467→            'sfuser_id', 'process_key', 'context', 'files', 'authorized_token', 'info', 'allowance_start_date', 'version',
468→        ]);
469→
470→        if (!in_array($input['process_key'], static::ALLOWED_IMPORT_PROCESS_KEYS)) {
471→            return $this->responseJsonFail(__('my_api.can_not_import'), ExceptionCode::ERR_USER_OPERATE_LIMIT);
472→        }
473→
474→        $sfuserId = $input['sfuser_id'];
475→
476→        // 检查输入
477→        $version = $input['version'] ?? 0;
478→        WorkflowRequestService::checkInput($input['process_key'], $sfuserId, $input['context'], $version);
479→
480→        Stakeholder::checkStakeholders($input, $sfuserId);
481→
482→        // 导入时不发送任何消息
483→        WorkflowRequestService::$cancelNotification = true;
484→
485→        // 自动抛出异常，不用 catch，返回给客户端
486→        $wr = WorkflowRequestService::make($input['process_key'], $input['sfuser_id'], $input['context'], (array)Arr::get($input, 'files', []));
487→
488→        // 请求实例生成完后，更新 token
489→        $wr->getRequest()->update([
490→            'token' => $input['authorized_token'] ?? '',
491→            'info' => $input['info'] ?? [],
492→            'created_at' => date(Arr::get($input, 'context.contract_start_date', date('Y-m-d')).' 00:00:00'),
493→        ]);
494→
495→        $requestId = $wr->getRequest()->id;
496→        // 房补补交材料之后，流程要自动变更为已通过，如此才能不用再走一遍审批流
497→        $rentAllowanceSfuserId = Stakeholder::fetchSfuserIdsViaType(
498→            WorkflowRequestStakeholder::RENT_ALLOWANCE_DIRECT_SUPERVISOR_TYPE,
499→            $requestId
500→        );
501→        $awr = new WorkflowRequestService($requestId, $rentAllowanceSfuserId);
502→        $awr->performAction(Action::APPROVE); // 同意，表示通过
503→
504→        // 最后更新一下房补记录表的补贴开始时间
505→        if (Arr::has($input, 'allowance_start_date')) {
506→            RentAllowanceLog::where('request_id', $requestId)->update([
507→                'allowance_start_date' => $input['allowance_start_date'],
508→            ]);
509→        }
510→
511→        return $this->responseJsonSuccess(['success' => true]);
512→    }
