 128→    /**
 129→     * 批量更新个人数目.
 130→     *
 131→     * @param array $sfuserIds
 132→     * @param string $type
 133→     * @param int $delta
 134→     * @return void
 135→     */
 136→    public function modifyMultiple(array $sfuserIds, string $type, int $delta = 1)
 137→    {
 138→        if (empty($sfuserIds)) {
 139→            return;
 140→        }
 141→        // 批量时也打每个人的变化日志，便于追踪待办变化过程
 142→        foreach ($sfuserIds as $sfuserId) {
 143→            $this->modifyIndividual($sfuserId, $type, $delta);
 144→        }
 145→    }
