 147→    /**
 148→     * 更新个人数目.
 149→     *
 150→     * @param int $sfuserId
 151→     * @param string $type
 152→     * @param int $delta
 153→     * @param bool $logChange 是否打日志（为 true 时记录该用户的待办变化 old->new）
 154→     * @return int
 155→     */
 156→    public function modifyIndividual(int $sfuserId, string $type, int $delta = 1, bool $logChange = true): int
 157→    {
 158→        if (!in_array($type, static::NOTIFY_TYPES)) {
 159→            info('[NotifyNumber] 无效的待办类型，跳过更新', ['sfuserId' => $sfuserId, 'type' => $type]);
 160→            return 0;
 161→        }
 162→        $redisKey = config('my_project.site_key').':'.static::REDIS_KEY_PREFIX.$sfuserId;
 163→
 164→        $oldValue = (int)redis('shared')->hget($redisKey, $type);
 165→        if (!redis('shared')->exists($redisKey)) {
 166→            $ret = redis('shared')->hincrby($redisKey, $type, $delta);
 167→
 168→            redis('shared')->expire($redisKey, static::TTL);
 169→            redis('shared')->sadd(config('my_project.site_key').':'.static::REDIS_KEY_SFUSER_IDS, $sfuserId);
 170→        } else {
 171→            $ret = redis('shared')->hincrby($redisKey, $type, $delta);
 172→        }
 173→
 174→        if ($logChange && $oldValue != $ret) {
 175→            info('[NotifyNumber] 待办变化', [
 176→                'sfuserId' => $sfuserId,
 177→                'type' => $type,
 178→                'delta' => $delta,
 179→                'old' => $oldValue,
 180→                'new' => $ret,
 181→            ]);
 182→        }
 183→
 184→        $this->addNotifySfusers($sfuserId);
 185→
 186→        return $ret;
 187→    }
