const fs = require('fs');
let c = fs.readFileSync('app/Service/KnockService.php', 'utf8');
let lines = c.split('\n');
let result = [];
let i = 0;

while (i < lines.length) {
    if (lines[i].trim() === '<<<<<<< HEAD') {
        // Collect HEAD lines
        let headLines = [];
        i++;
        while (i < lines.length && lines[i].trim() !== '=======') {
            headLines.push(lines[i]);
            i++;
        }
        // Skip =======
        i++;
        // Collect release lines
        let releaseLines = [];
        while (i < lines.length && !lines[i].trim().startsWith('>>>>>>> lbl-260416-release')) {
            releaseLines.push(lines[i]);
            i++;
        }
        // Skip >>>>>>>
        i++;

        // Now merge: keep both HEAD and release lines
        // For the first two conflicts (approve/reject messages):
        // HEAD has AI_PERMISSION elseif + else
        // Release has else + RENT_ALLOWANCE block
        // We want: AI_PERMISSION elseif, then else with RENT_ALLOWANCE block

        let headStr = headLines.join('\n');
        let releaseStr = releaseLines.join('\n');

        if (headStr.includes('AI_PERMISSION') && releaseStr.includes('RENT_ALLOWANCE')) {
            // Keep HEAD lines (AI_PERMISSION elseif + else), then insert release's rent allowance block before the foreach
            result.push(...headLines);
            // Extract the rent allowance block from release (skip the "} else {" line)
            let rentLines = releaseLines.filter(l => !l.trim().startsWith('} else {'));
            result.push(...rentLines);
        } else if (headStr.includes('sendDepartmentChangeMessage')) {
            // Third conflict: keep all HEAD functions, use release's method signature
            result.push(...headLines);
            // Release has the updated signature with $allowance_end_date parameter
            result.push(...releaseLines);
        } else {
            // Default: keep both
            result.push(...headLines);
            result.push(...releaseLines);
        }
    } else {
        result.push(lines[i]);
        i++;
    }
}

fs.writeFileSync('app/Service/KnockService.php', result.join('\n'));
let remaining = result.filter(l => l.includes('<<<<<<< HEAD')).length;
console.log('Remaining conflicts:', remaining);
